/** ------------------------------------------------------------------------------------------
 * 3. THE BEANSTALK BONUS FORMULA — VERIFIED VERBATIM against N.js. Both the jade-emporium gate
 * AND the rank->bonus math were found and confirmed against ground truth; nothing below is
 * guessed or carried over unverified from toolbox.
 *
 * SOURCE: `r._customBlock_GoldFoodBonuses=function(d){...}`, N.js byte offset 4969552-4972~.
 * Full function reads, in order:
 *
 *   (a) GfoodBonusMULTI = the general "Golden Food multi" (toolbox's `getGoldenFoodMulti`,
 *       misc.ts:769-885) — computed inline in the SAME N.js function, byte offset ~4969600-4971600.
 *       OUT OF SCOPE for this file per task brief (20+ unrelated systems); its only W6 tie-in is
 *       `m._customBlock_Summoning("VaultUpgBonus",86,0)`, i.e. Vault upgrade id 86 — already in
 *       `gamedata.mjs`: `VAULT_COEFF[86] === 1` (gamedata.mjs:99) and id 86 is in the
 *       `VAULT_NO_MASTERY` exempt list (gamedata.mjs:103, no mastery multiplier applied to it).
 *       NOTE (found while verifying, flagged for whoever eventually builds this recipe): the
 *       real N.js formula does NOT include a gear-based additive term the way toolbox's
 *       `getGoldenFoodMulti` does (`gearGoldFoodBonus` from `getStatsFromGear(character,8,...)`
 *       has no N.js counterpart in this function — possible toolbox inaccuracy or vestige), and
 *       N.js has TWO separate capped card terms (`min(4*CardLv("cropfallEvent1"),50) +
 *       min(5*CardLv("anni5Event1"),50)`) where toolbox collapses them into ONE
 *       (`min(getCardBonusByEffect(...,'Gold_Food_Effect_(Passive)'),50)`). Everything else
 *       (armor set SECRET_SET, family bonus, obols, talent id99, stamp "GFood", achievement 37,
 *       bubble GFoodz, sigil id14, meal zGoldFood, star sign id69, bribe id36, charm/PristineBon
 *       id14, achievements 380/383 weighted 2x/3x, vote id26, apocalypse-wow talent id209 combo,
 *       companion 48, legend talent id25, companion 155, vault 86) matches toolbox term-for-term.
 *
 *   (b) BASE bonus (any equipped golden food, scales with owned/equipped stack size) — the
 *       "normal" curve, N.js byte offset ~4972060-4972220, verbatim:
 *         GfoodBonus = Amount * GfoodBonusMULTI * .05
 *           * getLOG(1 + EquipmentQuantity[2][slotIdx])
 *           * (1 + getLOG(1 + EquipmentQuantity[2][slotIdx]) / 2.14)
 *       where `slotIdx` loops over the character's equipped food slots (0..FoodSlotsOwned-1) and
 *       only the slot whose item's `Effect` matches the caller's requested stat `d` contributes.
 *       `getLOG(x)` = `k._customBlock_getLOG`, N.js byte offset 4381353, verbatim
 *       `Math.log(Math.max(a,1))/2.30259` — a log10-equivalent (2.30259 ≈ ln(10)); this is
 *       EXACTLY toolbox's `lavaLog` (utility/helpers.js:351-353, byte-for-byte same constant).
 *
 *   (c) BEANSTALK bonus (gated, additive ON TOP of (b)) — N.js byte offset ~4971713-4972550:
 *         if (1 == Ninja("EmporiumBonus",1,0))            // jade emporium unlock check
 *           for e in 0..floor(NinjaInfo[29].length/3)-1:   // beanstalk slot index
 *             itemKey = NinjaInfo[29][2+3*e]
 *             if (ItemDefinitionsGET[itemKey].Effect == d) {
 *               if (Ninja[104][e] > 0)                      // beanstalkData[e] = rank, 0=not planted
 *                 GfoodBonus = GfoodBonus                    // ADDS to the base bonus from (b)
 *                   + ItemDefinitionsGET[itemKey].Amount * GfoodBonusMULTI * .05
 *                     * getLOG(1 + 1000 * Math.pow(10, Ninja[104][e]))
 *                     * (1 + getLOG(1 + 1000 * Math.pow(10, Ninja[104][e])) / 2.14)
 *               break   // unconditional once the Effect match is found, active or not
 *             }
 *
 *       `Ninja("EmporiumBonus",1,0)` (N.js byte offset 10592467, verbatim:
 *         `return -1 != (""+Ninja[102][9]).indexOf(""+Number2Letter[b|0]) ? 1 : 0`)
 *       checks whether jade-emporium row index `b`=1 is unlocked, by looking for its encoded
 *       letter inside `Ninja[102][9]` (the jade-unlocks bitstring — matches toolbox's
 *       `jadeEmporiumUnlocks = rawSneaking[102][9]` / `isJadeBonusUnlocked`). Row index 1 in
 *       `na.JadeUpg` (N.js byte offset 13717932, bracket-matched to isolate just this row) IS
 *       "Gold_Food_Beanstalk" — CONFIRMED by direct extraction, verbatim:
 *         "Gold_Food_Beanstalk 500 1 1 filler filler Grows_a_giant_beanstalk_behind_the_ninja_
 *          castle!_Drop_a_stack_of_10,000_Gold_Food_to_add_it_with_the_beanstalk_and_
 *          permanently_gain_its_bonus!"
 *       Row index 2 is "Supersized_Gold_Beanstacking" (same source, verbatim):
 *         "Supersized_Gold_Beanstacking 500 1 2 filler filler You_can_now_drop_a_stack_of_
 *          100,000_Gold_Food_to_supersize_it!_This_will_obviously_give_a_bigger_bonus,_and_will_
 *          even_enlargen_the_food_on_the_stalk!"
 *       NOTE: index 2 ("Supersized...") does NOT appear anywhere in the bonus-formula gate above
 *       — only index 1 does. This means Supersized_Gold_Beanstacking gates the DEPOSIT ACTION
 *       (letting a player push a food's rank from 1 to 2 by dropping a 100,000-stack), not the
 *       bonus math itself — the `1E3*Math.pow(10,rank)` formula already scales automatically for
 *       any rank value once deposited; the deposit-action gate code was not located in this pass
 *       (out of scope — the deliverable here is the resulting bonus formula, which is confirmed).
 *
 * VERIFICATION RESULT: the `1000 * 10^rank` term is a clean, self-consistent match to the jade
 * flavor text: rank 1 (a planted 10,000-stack) -> `1000*10^1 = 10,000`; rank 2 (a supersized
 * 100,000-stack) -> `1000*10^2 = 100,000`. `toolbox`'s beanstalk.jsx page independently uses
 * `breakpoints = [10000, 100000, 1e6]` indexed by rank to show "progress to next tier" — same
 * three numbers, same order, corroborating both the 10,000/100,000 tier sizes AND that rank can
 * reach (at least) 3, with a 1,000,000-stack quest (`Sad_Urie1`, N.js byte offset ~14973199:
 * "Bring_a_stack_of_1_million_of_any_golden_food,_and_you'll_unlock_a_new_Beanstalk_mechanic!")
 * gating whatever rank-3 mechanic exists beyond Supersized — NOT chased further here (no formula
 * change tied to rank 3 was found in `_customBlock_GoldFoodBonuses` itself; the `Math.pow(10,rank)`
 * term handles rank 3 automatically as `1000*10^3 = 1,000,000` if/when it's reachable).
 * ------------------------------------------------------------------------------------------ */

/** getLOG(x) = k._customBlock_getLOG, N.js byte offset 4381353, verbatim
 *  `Math.log(Math.max(a,1))/2.30259` (log10-equivalent; identical to toolbox's `lavaLog`). */
export function getLOG(x) {
  return Math.log(Math.max(x, 1)) / 2.30259;
}

/** The base (non-beanstalk) golden-food bonus for one equipped food, N.js byte offset
 *  ~4972060-4972220, verbatim: `Amount*GfoodBonusMULTI*.05*getLOG(1+qty)*(1+getLOG(1+qty)/2.14)`.
 *  `amount` = the food's ItemDefinitionsGET.Amount (see GOLDEN_FOODS). `qty` =
 *  `EquipmentQuantity[2][slotIdx]`, the owned/stacked count in that equipped food slot (save
 *  state, not extracted here). `gfoodBonusMulti` = GfoodBonusMULTI, the general Golden Food
 *  multi (section 3a, out of scope — pass 1 if evaluating in isolation). */
export function goldenFoodBaseBonus(amount, gfoodBonusMulti, qty) {
  const l = getLOG(1 + qty);
  return amount * gfoodBonusMulti * 0.05 * l * (1 + l / 2.14);
}

/** The beanstalk-specific bonus term for one planted food, N.js byte offset ~4972220-4972550,
 *  verbatim: `Amount*GfoodBonusMULTI*.05*getLOG(1+1000*10^rank)*(1+getLOG(1+1000*10^rank)/2.14)`.
 *  ADDITIVE on top of goldenFoodBaseBonus for the SAME stat (they are summed by the client, not
 *  mutually exclusive — a food can be both equipped AND planted on the beanstalk). `rank` =
 *  `Ninja[104][beanstalkIndex]` (0 = not planted; gate this to only call when `rank > 0`, per
 *  N.js's `0<Ninja[104][e]` check). Returns 0 semantics: caller should skip entirely when
 *  `rank <= 0` (matches N.js — no term is added, base bonus is untouched). */
export function beanstalkBonusTerm(amount, gfoodBonusMulti, rank) {
  const x = 1 + 1000 * Math.pow(10, rank);
  const l = getLOG(x);
  return amount * gfoodBonusMulti * 0.05 * l * (1 + l / 2.14);
}

/** Deposit thresholds (in Gold Food count) to ADVANCE from the current rank to the next —
 *  UNVERIFIED against N.js as a formula (no deposit-action dispatcher was located in this pass,
 *  see the NOTE in section 3), but sourced from idleon-toolbox's `beanstalk.jsx:15`
 *  (`const breakpoints = [10000, 100000, 1e6]`, indexed by current rank) and independently
 *  corroborated by: the jade flavor text's "10,000"/"100,000" stack sizes (ranks 1/2), and the
 *  `Sad_Urie1` quest's literal "1 million" golden food requirement (byte offset 14973199) which
 *  the quest describes as unlocking "a new Beanstalk mechanic" (likely rank 3, not chased here). */
export const BEANSTALK_RANK_THRESHOLDS = [10000, 100000, 1000000];

